#include <iostream>
#include <memory>  // for smart pointers
using namespace std;

// Raw pointer (dangerous)
void rawExample() {
    int* p = new int(42);
    // If exception occurs here or early return, memory leaks
    delete p;  // easy to forget
}

// Smart pointer (safe)
void smartExample() {
    unique_ptr<int> p = make_unique<int>(42);
    // Automatically deleted when p goes out of scope
}

int main() {
    smartExample();
    cout << "No memory leak" << endl;
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource() { cout << "Resource acquired" << endl; }
    ~Resource() { cout << "Resource released" << endl; }
    void work() { cout << "Working..." << endl; }
};

int main() {
    // Create unique_ptr
    unique_ptr<Resource> p1 = make_unique<Resource>();
    p1->work();

    // Cannot copy
    // unique_ptr<Resource> p2 = p1;  // ERROR: copy constructor deleted

    // Can move (transfer ownership)
    unique_ptr<Resource> p2 = move(p1);
    if (p1 == nullptr) cout << "p1 is now null" << endl;
    p2->work();

    // Release ownership (raw pointer, careful!)
    Resource* raw = p2.release();  // p2 no longer manages it
    delete raw;  // must delete manually

    // Reset to delete current and optionally point to new
    unique_ptr<Resource> p3 = make_unique<Resource>();
    p3.reset();  // deletes object, p3 becomes null
    p3.reset(new Resource());  // delete old, take new

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

struct Point {
    int x, y;
    Point(int a, int b) : x(a), y(b) {}
};

int main() {
    // Raw new (avoid)
    unique_ptr<int> p1(new int(42));

    // Better: make_unique
    auto p2 = make_unique<int>(42);
    auto p3 = make_unique<Point>(10, 20);
    auto p4 = make_unique<int[]>(5);  // array version

    cout << *p2 << endl;
    cout << p3->x << ", " << p3->y << endl;

    // For arrays
    for (int i = 0; i < 5; i++) {
        p4[i] = i * 10;
        cout << p4[i] << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Data {
public:
    int value;
    Data(int v) : value(v) { cout << "Data created" << endl; }
    ~Data() { cout << "Data destroyed" << endl; }
};

int main() {
    // Create shared_ptr
    shared_ptr<Data> sp1 = make_shared<Data>(100);
    cout << "Use count: " << sp1.use_count() << endl;  // 1

    // Copy (share ownership)
    shared_ptr<Data> sp2 = sp1;
    cout << "Use count: " << sp1.use_count() << endl;  // 2

    // Another copy
    shared_ptr<Data> sp3 = sp2;
    cout << "Use count: " << sp1.use_count() << endl;  // 3

    // Reset one
    sp2.reset();
    cout << "After reset sp2, count: " << sp1.use_count() << endl;  // 2

    // Access object
    cout << "Value: " << sp1->value << endl;

    // sp3 goes out of scope, then sp1, object destroyed
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

struct Widget {
    int id;
    Widget(int i) : id(i) { cout << "Widget " << id << " created" << endl; }
    ~Widget() { cout << "Widget " << id << " destroyed" << endl; }
};

int main() {
    // Efficient: single allocation
    auto sp1 = make_shared<Widget>(1);

    // Less efficient: separate allocations
    // shared_ptr<Widget> sp2(new Widget(2));  // avoid

    // With custom deleter (rare), you must use new
    auto sp3 = shared_ptr<Widget>(new Widget(3), [](Widget* w) {
        cout << "Custom deleter" << endl;
        delete w;
    });

    // For arrays (C++17)
    shared_ptr<int[]> arr = make_shared<int[]>(10);
    arr[0] = 42;
    cout << arr[0] << endl;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

int main() {
    shared_ptr<int> sp = make_shared<int>(42);
    weak_ptr<int> wp = sp;  // wp observes, doesn't own

    cout << "Use count: " << sp.use_count() << endl;  // still 1

    // Check if the object still exists
    if (auto locked = wp.lock()) {  // returns shared_ptr if alive
        cout << "Value: " << *locked << endl;
    } else {
        cout << "Object is gone" << endl;
    }

    // Reset the shared_ptr
    sp.reset();

    // Now wp is expired
    if (wp.expired()) {
        cout << "weak_ptr is expired" << endl;
    }

    // lock() returns nullptr
    auto locked = wp.lock();
    if (!locked) cout << "Can't lock, object dead" << endl;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

struct Node;  // forward declaration

struct Node {
    int data;
    shared_ptr<Node> next;   // owns next
    // To break cycle, one direction should be weak_ptr:
    // weak_ptr<Node> prev;   // non-owning back pointer

    Node(int d) : data(d) { cout << "Node " << data << " created" << endl; }
    ~Node() { cout << "Node " << data << " destroyed" << endl; }
};

int main() {
    // Leak: circular reference
    {
        auto a = make_shared<Node>(1);
        auto b = make_shared<Node>(2);
        a->next = b;
        b->next = a;  // cycle! Both reference counts remain 1 when out of scope
        // When block ends, a and b destroyed, but their reference counts are 1 (each points to other)
        // Memory leak!
    }
    cout << "After block, nodes not destroyed (leak)" << endl;

    // Fix: use weak_ptr
    struct SafeNode {
        int data;
        shared_ptr<SafeNode> next;
        weak_ptr<SafeNode> prev;  // weak prevents cycle
        SafeNode(int d) : data(d) { cout << "SafeNode " << data << " created" << endl; }
        ~SafeNode() { cout << "SafeNode " << data << " destroyed" << endl; }
    };

    {
        auto a = make_shared<SafeNode>(1);
        auto b = make_shared<SafeNode>(2);
        a->next = b;
        b->prev = a;  // weak, no count increase
        // No cycle
    }
    cout << "After block, SafeNodes destroyed" << endl;

    return 0;
}

#include <iostream>
#include <memory>
#include <cstdio>
using namespace std;

int main() {
    // unique_ptr with custom deleter (lambda)
    auto fileDeleter = [](FILE* f) {
        if (f) {
            cout << "Closing file" << endl;
            fclose(f);
        }
    };

    unique_ptr<FILE, decltype(fileDeleter)> filePtr(fopen("test.txt", "w"), fileDeleter);
    if (filePtr) {
        fprintf(filePtr.get(), "Hello\n");
    }
    // file automatically closed

    // For arrays with unique_ptr (C++11 had to use custom deleter)
    // C++14 and later: unique_ptr<int[]> works directly
    unique_ptr<int[]> arr(new int[10]);  // OK in C++14/17

    // shared_ptr with custom deleter
    auto deleter = [](int* p) {
        cout << "Deleting int: " << *p << endl;
        delete p;
    };
    shared_ptr<int> sp(new int(42), deleter);

    // For malloc/free
    auto mallocDeleter = [](int* p) { free(p); };
    unique_ptr<int, decltype(mallocDeleter)> mPtr((int*)malloc(sizeof(int)), mallocDeleter);
    *mPtr = 99;

    return 0;
}

#include <iostream>
#include <vector>
#include <memory>
#include <algorithm>
using namespace std;

class Shape {
public:
    virtual void draw() const = 0;
    virtual ~Shape() = default;
};

class Circle : public Shape {
public:
    void draw() const override { cout << "Circle" << endl; }
};

class Square : public Shape {
public:
    void draw() const override { cout << "Square" << endl; }
};

int main() {
    // Vector of unique_ptr
    vector<unique_ptr<Shape>> shapes;
    shapes.push_back(make_unique<Circle>());
    shapes.push_back(make_unique<Square>());

    for (const auto& s : shapes) {
        s->draw();
    }
    // Automatically cleaned

    // Vector of shared_ptr (if sharing needed)
    vector<shared_ptr<Shape>> sharedShapes;
    auto circle = make_shared<Circle>();
    sharedShapes.push_back(circle);
    sharedShapes.push_back(circle);  // same object, ref count 2

    cout << "Shared count: " << circle.use_count() << endl;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

// Example: factory function returning unique_ptr
unique_ptr<int> createInt(int value) {
    return make_unique<int>(value);
}

// Example: function that shares ownership
void observe(shared_ptr<int> sp) {
    cout << "Observing: " << *sp << ", use_count: " << sp.use_count() << endl;
}

int main() {
    // Rule: Prefer unique_ptr unless you need shared
    auto u = createInt(42);

    // Transfer ownership to a function
    auto receive = [](unique_ptr<int> p) {
        cout << "Received: " << *p << endl;
    };
    receive(move(u));  // u is now null

    // shared_ptr when multiple parts of code need access
    auto s1 = make_shared<int>(100);
    observe(s1);
    auto s2 = s1;  // share
    observe(s1);

    // weak_ptr when you need to observe without owning
    weak_ptr<int> w = s1;
    if (auto locked = w.lock()) {
        cout << "Still alive: " << *locked << endl;
    }

    return 0;
}
